PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?decade(COUNT(?scoring_leader) AS ?total)(SUM(IF(EXISTS {
  ?scoring_leader wdt:P1991 wd:Q13407712
}
, 1 , 0)) AS ?centers)(ROUND((SUM(IF(EXISTS {
  ?scoring_leader wdt:P1991 wd:Q13407712
}
, 1 , 0)) * 100.0) / COUNT(?scoring_leader)) AS ?percentage) WHERE {
  ?season wdt:P31 wd:Q1178004 ; wdt:P585 ?season_date ; wdt:P1987 ?scoring_leader .
  BIND(SUBSTR(STR(?season_date) , 1 , 4) AS ?year_str)
  .
  BIND(CONCAT(SUBSTR(?year_str , 1 , 3) , '0') AS ?decade)
  .
}
GROUP BY ?decade
ORDER BY ?decade
